"""Arithmetic helpers."""


def add(a, b):
    return a + b


def divide(a, b):
    if b == 0:
        raise ZeroDivisionError("b must be non-zero")
    return a / b


def average(nums):
    """Return the arithmetic mean of nums."""
    if not nums:
        raise ValueError("nums must be non-empty")
    return sum(nums) / len(nums)
